/**
 * @file fft_radix3_avx2_ct_t1_dit.h
 * @brief DFT-3 AVX2 t1 DIT (in-place twiddle)
 *
 * FFTW-style codelet for recursive CT executor.
 * Generated by gen_radix3.py --variant ct_t1_dit
 */

#ifndef FFT_RADIX3_AVX2_CT_CT_T1_DIT_H
#define FFT_RADIX3_AVX2_CT_CT_T1_DIT_H

#include <immintrin.h>

#ifndef R3A_CT_LD
#define R3A_CT_LD(p) _mm256_loadu_pd(p)
#define R3A_CT_ST(p,v) _mm256_storeu_pd((p),(v))
#endif
#define LD R3A_CT_LD
#define ST R3A_CT_ST

static __attribute__((target("avx2,fma"))) void
radix3_t1_dit_fwd_avx2(
    double * __restrict__ rio_re, double * __restrict__ rio_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t ios, size_t me)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS    = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t m = 0; m < me; m += 4) {
        x0_re = LD(&rio_re[m+0*ios]);
        x0_im = LD(&rio_im[m+0*ios]);
        x1_re = LD(&rio_re[m+1*ios]);
        x1_im = LD(&rio_im[m+1*ios]);
        x2_re = LD(&rio_re[m+2*ios]);
        x2_im = LD(&rio_im[m+2*ios]);
        { const __m256d wr = LD(&W_re[0*me+m]);
          const __m256d wi = LD(&W_im[0*me+m]);
          const __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,wr,_mm256_mul_pd(x1_im,wi));
          x1_im = _mm256_fmadd_pd(tr,wi,_mm256_mul_pd(x1_im,wr)); }
        { const __m256d wr = LD(&W_re[1*me+m]);
          const __m256d wi = LD(&W_im[1*me+m]);
          const __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,wr,_mm256_mul_pd(x2_im,wi));
          x2_im = _mm256_fmadd_pd(tr,wi,_mm256_mul_pd(x2_im,wr)); }

        /* DFT-3 butterfly [fwd] */
        __m256d ar=_mm256_add_pd(x1_re,x2_re), ai=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d R1r=_mm256_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm256_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm256_add_pd(x0_re,ar); x0_im=_mm256_add_pd(x0_im,ai);
        x1_re=_mm256_fmadd_pd(KS,di,R1r); x1_im=_mm256_fnmadd_pd(KS,dr,R1i);
        x2_re=_mm256_fnmadd_pd(KS,di,R1r); x2_im=_mm256_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], x0_re);
        ST(&rio_im[m+0*ios], x0_im);
        ST(&rio_re[m+1*ios], x1_re);
        ST(&rio_im[m+1*ios], x1_im);
        ST(&rio_re[m+2*ios], x2_re);
        ST(&rio_im[m+2*ios], x2_im);
    }
}

static __attribute__((target("avx2,fma"))) void
radix3_t1_dit_bwd_avx2(
    double * __restrict__ rio_re, double * __restrict__ rio_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t ios, size_t me)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS    = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t m = 0; m < me; m += 4) {
        x0_re = LD(&rio_re[m+0*ios]);
        x0_im = LD(&rio_im[m+0*ios]);
        x1_re = LD(&rio_re[m+1*ios]);
        x1_im = LD(&rio_im[m+1*ios]);
        x2_re = LD(&rio_re[m+2*ios]);
        x2_im = LD(&rio_im[m+2*ios]);
        { const __m256d wr = LD(&W_re[0*me+m]);
          const __m256d wi = LD(&W_im[0*me+m]);
          const __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,wr,_mm256_mul_pd(x1_im,wi));
          x1_im = _mm256_fmsub_pd(x1_im,wr,_mm256_mul_pd(tr,wi)); }
        { const __m256d wr = LD(&W_re[1*me+m]);
          const __m256d wi = LD(&W_im[1*me+m]);
          const __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,wr,_mm256_mul_pd(x2_im,wi));
          x2_im = _mm256_fmsub_pd(x2_im,wr,_mm256_mul_pd(tr,wi)); }

        /* DFT-3 butterfly [bwd] */
        __m256d ar=_mm256_add_pd(x1_re,x2_re), ai=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d R1r=_mm256_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm256_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm256_add_pd(x0_re,ar); x0_im=_mm256_add_pd(x0_im,ai);
        x2_re=_mm256_fmadd_pd(KS,di,R1r); x2_im=_mm256_fnmadd_pd(KS,dr,R1i);
        x1_re=_mm256_fnmadd_pd(KS,di,R1r); x1_im=_mm256_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], x0_re);
        ST(&rio_im[m+0*ios], x0_im);
        ST(&rio_re[m+1*ios], x1_re);
        ST(&rio_im[m+1*ios], x1_im);
        ST(&rio_re[m+2*ios], x2_re);
        ST(&rio_im[m+2*ios], x2_im);
    }
}


#undef LD
#undef ST

#endif /* FFT_RADIX3_AVX2_CT_CT_T1_DIT_H */
